"""Install dashboard hooks: copy relay script + merge hook config into Claude settings.

Deep merge strategy (matching ~/source/my-claude-stuff/scripts/reconcile.py):
- Dicts: recursively merged, source wins on conflicts
- Lists: union with deduplication (JSON serialization as key)
- Scalars: source overwrites
- Dest-only keys: preserved
"""

import argparse
import json
import logging
import logging.handlers
import os
import shutil
import sys
from pathlib import Path

EXIT_SUCCESS = 0
EXIT_ERROR = 1

logger = logging.getLogger(__name__)

PROJECT_ROOT = Path(__file__).resolve().parent.parent
HOOKS_SETTINGS = PROJECT_ROOT / "hooks-settings.json"
RELAY_SCRIPT = PROJECT_ROOT / "scripts" / "hook_relay.py"
CLAUDE_SETTINGS = Path.home() / ".claude" / "settings.json"
INSTALL_DIR = Path.home() / ".claude" / "claude-dashboard" / "scripts"


_RELAY_MARKER = ".claude/claude-dashboard/scripts/hook_relay.py"


def _hook_entry_key(item: object) -> str | None:
    """Extract a stable identity key from a hook rule entry.

    Hook rules look like: {"hooks": [{"type": "command", "command": "...hook_relay.py ..."}]}
    Returns the script basename (e.g. "hook_relay.py") so that command-line
    flag changes (like adding --debug) replace the existing entry instead of
    duplicating it.
    """
    if not isinstance(item, dict):
        return None
    hooks = item.get("hooks")
    if not isinstance(hooks, list):
        return None
    for hook in hooks:
        if isinstance(hook, dict):
            cmd = hook.get("command", "")
            if _RELAY_MARKER in cmd:
                return _RELAY_MARKER
    return None


def _deep_merge(src: dict, dest: dict) -> dict:
    """Merge src into dest recursively. Returns dest (mutated)."""
    for key, src_val in src.items():
        if key not in dest:
            dest[key] = src_val
        elif isinstance(src_val, dict) and isinstance(dest[key], dict):
            _deep_merge(src_val, dest[key])
        elif isinstance(src_val, list) and isinstance(dest[key], list):
            # Build index of dest items by hook identity key (if any)
            keyed_indices: dict[str, int] = {}
            for i, item in enumerate(dest[key]):
                hk = _hook_entry_key(item)
                if hk is not None:
                    keyed_indices[hk] = i

            existing = {json.dumps(item, sort_keys=True) for item in dest[key]}
            for item in src_val:
                hk = _hook_entry_key(item)
                if hk is not None and hk in keyed_indices:
                    # Replace existing hook entry in-place
                    dest[key][keyed_indices[hk]] = item
                else:
                    serialized = json.dumps(item, sort_keys=True)
                    if serialized not in existing:
                        dest[key].append(item)
                        existing.add(serialized)
        else:
            dest[key] = src_val
    return dest


def install_hooks(
    *,
    hooks_path: Path | None = None,
    settings_path: Path | None = None,
    dry_run: bool = False,
) -> bool:
    """Copy relay script and merge hook settings into Claude settings."""
    hooks_file = hooks_path or HOOKS_SETTINGS
    settings_file = settings_path or CLAUDE_SETTINGS

    if not hooks_file.exists():
        logger.error("hooks settings file not found path=%s", hooks_file)
        return False

    # Copy relay script to install location
    if not dry_run:
        INSTALL_DIR.mkdir(parents=True, exist_ok=True)
        dest_relay = INSTALL_DIR / "hook_relay.py"
        shutil.copy2(RELAY_SCRIPT, dest_relay)
        logger.info("relay script copied to %s", dest_relay)

    # Merge hook config
    src = json.loads(hooks_file.read_text(encoding="utf-8"))

    if settings_file.exists():
        dest = json.loads(settings_file.read_text(encoding="utf-8"))
    else:
        dest = {}

    merged = _deep_merge(src, dest)

    if dry_run:
        print(json.dumps(merged, indent=2))
        return True

    settings_file.parent.mkdir(parents=True, exist_ok=True)
    settings_file.write_text(
        json.dumps(merged, indent=2, ensure_ascii=False) + "\n",
        encoding="utf-8",
    )
    logger.info("hooks merged into %s", settings_file)
    return True


def _build_parser() -> argparse.ArgumentParser:
    parser = argparse.ArgumentParser(
        description="Install dashboard hooks into ~/.claude/settings.json."
    )
    parser.add_argument(
        "--dryrun",
        action="store_true",
        help="print the merged settings to stdout instead of writing",
    )
    parser.add_argument("--debug", action="store_true", help="enable debug logging")
    parser.add_argument(
        "--quiet", "-q", action="store_true", help="suppress non-essential output"
    )
    parser.add_argument(
        "--log-file", type=str, default=None, help="write log output to file"
    )
    return parser


def _configure_logging(*, debug: bool, quiet: bool, log_file: str | None) -> None:
    if quiet:
        level = logging.WARNING
    elif debug:
        level = logging.DEBUG
    else:
        level = logging.INFO
    log_fmt = "%(asctime)s %(levelname)s %(name)s: %(message)s"
    if log_file:
        log_path = str(Path(log_file).expanduser().resolve())
        os.makedirs(os.path.dirname(log_path), exist_ok=True)
        handler: logging.Handler = logging.handlers.RotatingFileHandler(
            log_path, maxBytes=2 * 1024 * 1024, backupCount=1, encoding="utf-8"
        )
        handler.setFormatter(logging.Formatter(log_fmt))
        logging.basicConfig(level=level, handlers=[handler])
    else:
        logging.basicConfig(level=level, format=log_fmt, stream=sys.stderr)


def main(argv: list[str] | None = None) -> int:
    args = _build_parser().parse_args(argv)
    _configure_logging(debug=args.debug, quiet=args.quiet, log_file=args.log_file)
    success = install_hooks(dry_run=args.dryrun)
    return EXIT_SUCCESS if success else EXIT_ERROR


if __name__ == "__main__":
    sys.exit(main())
